const items = $input.all();

return [
  {
    json: {
      run_id: items[0].json.run_id,
      triggered_by: "n8n",
      targets: items.map(i => ({
        month_key: i.json.month_key,
        dataset_version: i.json.dataset_version,
        source_type: i.json.source_type,
        url: i.json.source_url
      }))
    }
  }
];

// ===============================
// Build Slack Alert Message
// ===============================

// ---- Input: Summary Metrics ----
const summary = $input.first().json;

const ingested = Number(summary.ingested || 0);
const skipped = Number(summary.skipped_unchanged || 0);
const missing = Number(summary.skip_missing || 0);
const failed  = Number(summary.failed || 0);

// ---- Run Context (Zeitraum, Trigger) ----
const runContext = $node["DB_Create ingestion run"].json || {};
const triggeredBy = runContext.triggered_by || "unbekannt";

// ---- Zeitraum bestimmen ----
let periodText = "";

const hasValidRange =
  runContext.date_from &&
  runContext.date_to &&
  runContext.date_from !== "null" &&
  runContext.date_to !== "null";

if (hasValidRange) {
  // manueller Zeitraum
  periodText = `${runContext.date_from} – ${runContext.date_to}`;
} else {
  // Scheduler oder Fallback → aus Targets
  const targets = ($node["Aggregate targets"]?.json?.targets) || [];
  const monthKeys = [...new Set(targets.map(t => t.month_key))].sort();

  if (monthKeys.length === 1) {
    periodText = monthKeys[0];
  } else if (monthKeys.length > 1) {
    periodText = `${monthKeys[0]} – ${monthKeys[monthKeys.length - 1]}`;
  } else {
    periodText = "Zeitraum nicht verfügbar";
  }
}
// ---- Laufart ----
let runTypeText = "Manueller Lauf";
if (triggeredBy === "n8n") {
  runTypeText = "Automatischer Lauf (Scheduler)";
}

// ---- Bewertung & Status ----
let evaluationText = "";
let statusText = "";
let statusEmoji = "";

if (failed > 0) {
  statusEmoji = "🔴";
  evaluationText =
    "Während des Ingestion-Prozesses sind technische Fehler aufgetreten. " +
    "Die Verarbeitung konnte nicht vollständig abgeschlossen werden.";
  statusText = "Fehlerzustand – manuelle Prüfung erforderlich.";
} else if (ingested > 0) {
  statusEmoji = "🟢";
  evaluationText =
    "Es wurden neue oder aktualisierte Detektordaten erkannt und erfolgreich in die Datenbank geladen.";
  statusText = "Pipeline erfolgreich ausgeführt.";
} else if (missing > 0) {
  statusEmoji = "🟠";
  evaluationText =
    "Einige erwartete Dateien waren nicht verfügbar. " +
    "Die Pipeline blieb stabil, jedoch sind Datenlücken möglich.";
  statusText = "Teilweise Abweichungen – Monitoring empfohlen.";
} else {
  statusEmoji = "🟡";
  evaluationText =
    "Es wurden keine neuen oder geänderten Daten veröffentlicht. " +
    "Der Datenbestand ist weiterhin synchron mit dem letzten bekannten Stand.";
  statusText = "Stabiler Zustand – kein Handlungsbedarf.";
}

// ---- Slack Message (Markdown) ----
const message = `
 *Ingestion Monitoring – Verkehrsdetektion Berlin*

*Run Information*
▶️ *Laufart:* ${runTypeText}  
📅 *Verarbeiteter Zeitraum:* ${periodText}

*Ergebnis (letzter Lauf)*
🟢 *Neue / aktualisierte Dateien:* ${ingested}  
🟡 *Unveränderte Dateien (Skip):* ${skipped}  
🟠 *Fehlende Dateien (Missing):* ${missing}  
🔴 *Technische Fehler:* ${failed}

*Bewertung*
${evaluationText}

*Pipeline Status*
${statusEmoji} ${statusText}

_Überwachung via n8n · KPI Confidence Projekt_  
_Automated with this n8n workflow_
`.trim();

// ---- Output ----
return [
  {
    json: {
      slack_message: message,
    },
  },
];

const input = $input.first().json;
const runId = input.run_id;


// -----------------------------
// Parse YYYY-MM or YYYY_MM
// -----------------------------
function parseYYYYMM(s) {

  if (!s) return null;

  const clean = String(s).trim().replace("_", "-");
  const parts = clean.split("-");

  if (parts.length !== 2) return null;

  const y = parseInt(parts[0], 10);
  const m = parseInt(parts[1], 10);

  if (!y || !m || m < 1 || m > 12) return null;

  return { y, m };
}


// -----------------------------
// Generate month range
// -----------------------------
function generateMonths(fromY, fromM, toY, toM) {

  const months = [];

  let y = fromY;
  let m = fromM;

  while (y < toY || (y === toY && m <= toM)) {

    months.push({ year: y, month: m });

    m++;

    if (m > 12) {
      m = 1;
      y++;
    }

  }

  return months;

}


// -----------------------------
// Determine run scope
// -----------------------------
const fromParsed = parseYYYYMM(input.date_from);
const toParsed   = parseYYYYMM(input.date_to);

let fromYear, fromMonth, toYear, toMonth;


// ---------- MANUAL RUN ----------
if (fromParsed) {

  fromYear = fromParsed.y;
  fromMonth = fromParsed.m;

  if (toParsed) {
    toYear = toParsed.y;
    toMonth = toParsed.m;
  } else {
    toYear = fromYear;
    toMonth = fromMonth;
  }

}

// ---------- SCHEDULE RUN ----------
else {

  const now = new Date();

  let y = now.getFullYear();
  let m = now.getMonth(); // previous month

  if (m === 0) {
    y -= 1;
    m = 12;
  }

  fromYear = y;
  fromMonth = m;

  toYear = y;
  toMonth = m;

}

// -----------------------------
// Generate months
// -----------------------------
const months = generateMonths(fromYear, fromMonth, toYear, toMonth);


// -----------------------------
// Build targets
// -----------------------------
const targets = [];


months.forEach(({ year, month }) => {

  const monthStr = String(month).padStart(2, "0");
  const month_key = `${year}_${monthStr}`;


  // ---------- OLD DETECTORS ----------
  targets.push({
    json: {
      run_id: runId,
      triggered_by: "n8n",
      month_key,
      dataset_version: "old",
      source_type: "detectors",
      source_url:
        `https://mdhopendata.blob.core.windows.net/verkehrsdetektion/${year}/alte_qualitaetssicherung/Fahrstreifendetektoren/det_val_hr_${year}_${monthStr}.csv.gz`
    }
  });


  // ---------- OLD CROSS SECTIONS ----------
  targets.push({
    json: {
      run_id: runId,
      triggered_by: "n8n",
      month_key,
      dataset_version: "old",
      source_type: "cross_sections",
      source_url:
        `https://mdhopendata.blob.core.windows.net/verkehrsdetektion/${year}/alte_qualitaetssicherung/Messquerschnitte/mq_hr_${year}_${monthStr}.csv.gz`
    }
  });


  // ---------- NEW DETECTORS ----------

  const basePath =
    `https://mdhopendata.blob.core.windows.net/verkehrsdetektion/${year}/neue_qualitaetssicherung/Fahrstreifendetektoren/`;


  // rule: before 2025 only 1 filename
  // after 2026 both candidates
  const detectorCandidates = year >= 2025
    ? [
        `detektoren_${year}_${monthStr}.tgz`,
        `detektor_${year}_${monthStr}.tgz`
      ]
    : [
        `detektoren_${year}_${monthStr}.tgz`
      ];


  detectorCandidates.forEach(file => {

    targets.push({
      json: {
        run_id: runId,
        triggered_by: "n8n",
        month_key,
        dataset_version: "new",
        source_type: "detectors",
        source_url: basePath + file
      }
    });

  });

});


return targets;
